return [{
  json: {
    source: 'tms_webhook',
    tmsSystem: 'Tai Software',
    brokerId: 'BROKER_001',
    load: {
      id: 'LOAD-2026-8847',
      origin: { city: 'Dallas', state: 'TX', zip: '75201' },
      destination: { city: 'Atlanta', state: 'GA', zip: '30309' },
      distance: 780,
      equipment: 'Dry Van',
      weight: 42000,
      pickupDate: '2026-03-02',
      deliveryDate: '2026-03-04',
      commodity: 'Consumer Electronics',
      offerRate: 2100,
      maxRate: 2400
    },
    preferredCarriers: ['CAR_001', 'CAR_002', 'CAR_003']
  }
}];

const load = $input.first().json.load;

// Newtrul's Smart Matching algorithm
// Analyzes carrier preferences, history, equipment, location

const carriers = [
  {
    id: 'CAR_001',
    name: 'Swift Transportation',
    rating: 4.8,
    onTime: 0.96,
    equipment: ['Dry Van', 'Reefer'],
    preferredLanes: ['TX-GA', 'TX-FL', 'TX-NC'],
    currentLocation: { city: 'Houston', state: 'TX' },
    availableDate: '2026-03-01',
    acceptanceRate: 0.85,
    fraudScore: 0.02
  },
  {
    id: 'CAR_002',
    name: 'J.B. Hunt',
    rating: 4.9,
    onTime: 0.98,
    equipment: ['Dry Van', 'Flatbed'],
    preferredLanes: ['TX-GA', 'OK-TX'],
    currentLocation: { city: 'Dallas', state: 'TX' },
    availableDate: '2026-03-01',
    acceptanceRate: 0.75,
    fraudScore: 0.01
  },
  {
    id: 'CAR_003',
    name: 'Schneider',
    rating: 4.7,
    onTime: 0.94,
    equipment: ['Dry Van'],
    preferredLanes: ['TX-GA', 'TX-LA'],
    currentLocation: { city: 'San Antonio', state: 'TX' },
    availableDate: '2026-03-02',
    acceptanceRate: 0.80,
    fraudScore: 0.03
  },
  {
    id: 'CAR_004',
    name: 'Knight-Swift',
    rating: 4.6,
    onTime: 0.93,
    equipment: ['Dry Van', 'Reefer'],
    preferredLanes: ['TX-GA'],
    currentLocation: { city: 'Austin', state: 'TX' },
    availableDate: '2026-03-01',
    acceptanceRate: 0.88,
    fraudScore: 0.04
  }
];

// Smart matching score calculation
const scoredCarriers = carriers.map(carrier => {
  let score = 0;
  let reasons = [];

  // Lane preference match
  const laneKey = load.origin.state + '-' + load.destination.state;
  if (carrier.preferredLanes.includes(laneKey)) {
    score += 25;
    reasons.push('Preferred lane match');
  }

  // Equipment match
  if (carrier.equipment.includes(load.equipment)) {
    score += 20;
    reasons.push('Equipment match');
  }

  // Proximity to pickup
  const distanceFromPickup = Math.abs(['Houston', 'Dallas', 'San Antonio', 'Austin'].indexOf(carrier.currentLocation.city) - 0);
  score += (3 - distanceFromPickup) * 10;
  if (carrier.currentLocation.city === load.origin.city) {
    reasons.push('In pickup city');
  }

  // Performance
  score += carrier.rating * 5;
  score += carrier.onTime * 10;
  score += carrier.acceptanceRate * 15;

  // Fraud protection (Highway integration)
  score -= carrier.fraudScore * 100;
  if (carrier.fraudScore < 0.03) {
    reasons.push('Low fraud risk');
  }

  // Rate competitiveness
  const suggestedRate = load.distance * 2.8; // $2.80/mile market rate
  const rateAcceptance = load.offerRate >= suggestedRate ? 1.0 : load.offerRate / suggestedRate;
  score += rateAcceptance * 15;

  return {
    ...carrier,
    matchScore: Math.round(score),
    suggestedRate: Math.round(suggestedRate),
    reasons,
    bookable: score > 70 && carrier.fraudScore < 0.05
  };
}).sort((a, b) => b.matchScore - a.matchScore);

return [{
  json: {
    ...$input.first().json,
    scoredCarriers,
    topMatch: scoredCarriers[0],
    alternatives: scoredCarriers.slice(1, 3),
    digitalBookingAvailable: scoredCarriers[0].bookable
  }
}];

const data = $input.first().json;

// Digital Booking - Auto-negotiate and book
const topCarrier = data.topMatch;

// Try to negotiate 3% below offer rate
const negotiatedRate = Math.round(data.load.offerRate * 0.97);
const savings = data.load.offerRate - negotiatedRate;

// Check if carrier accepts negotiated rate
const carrierAccepts = negotiatedRate >= topCarrier.suggestedRate * 0.95;

return [{
  json: {
    ...data,
    negotiation: {
      originalOffer: data.load.offerRate,
      negotiatedRate: carrierAccepts ? negotiatedRate : data.load.offerRate,
      savings: carrierAccepts ? savings : 0,
      carrierAccepts,
      message: carrierAccepts 
        ? `${topCarrier.name} accepted negotiated rate of $${negotiatedRate}` 
        : `${topCarrier.name} requires original offer of $${data.load.offerRate}`
    },
    readyToBook: true
  }
}];

